  data = json.load(sys.stdin)
  local = [s for s in data if s.get('source')=='local']
  if local:
    for s in local:
      print(f'  LOCAL: {s[\"name\"]} ({s[\"wpVersion\"]})')
  else:
    print('  (no local sites)')
